import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Signup.css";

function Signup() {
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    username: "",
    password: "",
    confirmPassword: "",
    mobileNumber: "",
    role: "Freelancer"
  });

  const [errors, setErrors] = useState({});
  const [submitError, setSubmitError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
    if (errors[name]) setErrors({ ...errors, [name]: "" });
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formData.fullName.trim()) newErrors.fullName = "नाम आवश्यक है";
    if (!/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = "ईमेल सही नहीं है";
    if (formData.password.length < 6) newErrors.password = "पासवर्ड कम से कम 6 अक्षरों का हो";
    if (formData.password !== formData.confirmPassword) newErrors.confirmPassword = "पासवर्ड मैच नहीं हुए";
    if (formData.mobileNumber.length !== 10) newErrors.mobileNumber = "मोबाइल नंबर 10 अंकों का हो";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsLoading(true);
    setSubmitError("");

    try {
      const response = await fetch('http://localhost:3000/api/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok) {
        alert("अकाउंट बन गया! अब लॉगिन करें। 🎉");
        navigate("/login");
      } else {
        setSubmitError(data.msg || "रजिस्ट्रेशन फेल हो गया।");
      }
    } catch (error) {
      setSubmitError("सर्वर एरर! कृपया बैकएंड चेक करें।");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="signup-container">
      <div className="signup-card">
        <h2 className="signup-title">Join Us</h2>
        <p className="signup-subtitle">विद्यार्थियों के लिए खास मार्केटप्लेस</p>

        {submitError && <div className="error-box">{submitError}</div>}

        <form onSubmit={handleSubmit} className="signup-form">
          <div className="form-group">
            <label className="input-label">मैं जुड़ना चाहता हूँ:</label>
            <select name="role" value={formData.role} onChange={handleChange} className="signup-input">
              <option value="Freelancer">Freelancer</option>
              <option value="Client">Client (Hirer)</option>
            </select>
          </div>

          <input type="text" name="fullName" placeholder="पूरा नाम" value={formData.fullName} onChange={handleChange} className="signup-input" />
          {errors.fullName && <span className="err-txt">{errors.fullName}</span>}

          <input type="email" name="email" placeholder="ईमेल पता" value={formData.email} onChange={handleChange} className="signup-input" />
          {errors.email && <span className="err-txt">{errors.email}</span>}

          <div className="flex-row">
            <input type="text" name="username" placeholder="यूजरनेम" value={formData.username} onChange={handleChange} className="signup-input" />
            <input type="text" name="mobileNumber" placeholder="मोबाइल नंबर" value={formData.mobileNumber} onChange={handleChange} className="signup-input" />
          </div>

          <div className="flex-row">
            <input type="password" name="password" placeholder="पासवर्ड" value={formData.password} onChange={handleChange} className="signup-input" />
            <input type="password" name="confirmPassword" placeholder="पासवर्ड कन्फर्म करें" value={formData.confirmPassword} onChange={handleChange} className="signup-input" />
          </div>
          {errors.confirmPassword && <span className="err-txt">{errors.confirmPassword}</span>}

          <button type="submit" className="signup-btn" disabled={isLoading}>
            {isLoading ? <span className="spinner"></span> : "Register Now"}
          </button>
        </form>

        <p className="login-redirect">पहले से अकाउंट है? <span onClick={() => navigate("/login")}>Login</span></p>
      </div>
    </div>
  );
}

export default Signup;
